from beeai.memory import ConversationMemory
import re

INJECTION_REGEX = re.compile(
    r'(ignore.*instructions|you are.*(hacker|admin)|override|system prompt)',
    re.IGNORECASE
)

def scan_memory_poisoning(memory: ConversationMemory) -> list:
    poisoned_turns = []
    for i, turn in enumerate(memory.history):
        if INJECTION_REGEX.search(turn['content']):
            poisoned_turns.append({
                'turn': i,
                'content': turn['content'][:200],
                'role': turn['role']
            })
    if poisoned_turns:
        print(f"🚨 MEMORY POISONING: {len(poisoned_turns)} contaminated turns")
    return poisoned_turns

# Check before each agent response
agent.on('before_response', lambda ctx: scan_memory_poisoning(ctx.memory))

from beeai.models import GraniteModel
from pydantic import BaseModel, validator
from typing import Any, Dict

class SafeToolCall(BaseModel):
    name: str
    parameters: Dict[str, Any]

    @validator('parameters')
    def validate_params(cls, v):
        suspicious = ['eval', 'exec', 'import', 'os.system', 'curl']
        param_str = str(v)
        if any(s in param_str.lower() for s in suspicious):
            raise ValueError(f"Suspicious parameters detected: {param_str[:50]}...")
        return v

class GraniteOutputValidator:
    def __init__(self):
        self.model = GraniteModel()

    def validate_output(self, raw_output: str):
        try:
            parsed = SafeToolCall.parse_raw(raw_output)
            return True
        except Exception as e:
            print(f"🚨 GRANITE OUTPUT INJECTION: {e}")
            return False

# Integrate with BeeAI agent
validator = GraniteOutputValidator()
agent.on('model_output', lambda output: validator.validate_output(output.content))

